class LogWriter:
    """Thread-safe log file writer with rotation support."""
    
    def __init__(self, config):
        self.config = config
        self._lock = threading.Lock()
        self._ensure_log_dir()
    
    def _ensure_log_dir(self):
        os.makedirs(self.config.log_dir, exist_ok=True)
    
    def _get_file_size_mb(self):
        try:
            return os.path.getsize(self.config.log_path) / (1024 * 1024)
        except OSError:
            return 0
    
    def _rotate_logs(self):
        """Rotate log files when max size is exceeded."""
        if self._get_file_size_mb() < self.config.max_file_size_mb:
            return
        
        # Remove oldest backup if at limit
        oldest = "%s.%d" % (self.config.log_path, self.config.backup_count)
        if os.path.exists(oldest):
            os.remove(oldest)
        
        # Shift existing backups
        for i in range(self.config.backup_count - 1, 0, -1):
            src = "%s.%d" % (self.config.log_path, i)
            dst = "%s.%d" % (self.config.log_path, i + 1)
            if os.path.exists(src):
                os.rename(src, dst)
        
        # Rename current log to .1
        if os.path.exists(self.config.log_path):
            os.rename(self.config.log_path, "%s.1" % self.config.log_path)
    
    def write(self, service, level, message, metadata=None):
        """Write a formatted log entry to the log file."""
        timestamp = datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%S.%fZ")
        
        # Sanitize inputs to prevent log injection
        service = self._sanitize(service)
        level = self._sanitize(level).upper()
        message = self._sanitize(message)
        
        if metadata:
            meta_str = " | metadata=%s" % json.dumps(metadata)
        else:
            meta_str = ""
        
        log_line = "[%s] [%s] [%s] %s%s\n" % (timestamp, level, service, message, meta_str)
        
        with self._lock:
            self._rotate_logs()
            with open(self.config.log_path, "a", encoding="utf-8") as f:
                f.write(log_line)
        
        return log_line.strip()
    
    def _sanitize(self, value):
        """Sanitize input to prevent log injection attacks."""
        if not isinstance(value, str):
            value = str(value)
        # Remove newlines and carriage returns to prevent log injection
        return value.replace("\n", "\\n").replace("\r", "\\r")
    
    def read_logs(self, lines=100, service_filter=None, level_filter=None):
        """Read recent log entries with optional filtering."""
        with self._lock:
            if not os.path.exists(self.config.log_path):
                return []
            with open(self.config.log_path, "r", encoding="utf-8") as f:
                all_lines = f.readlines()
        
        result = []
        for line in all_lines:
            line = line.strip()
            if not line:
                continue
            if service_filter and ("[%s]" % service_filter) not in line:
                continue
            if level_filter and ("[%s]" % level_filter.upper()) not in line:
                continue
            result.append(line)
        
        return result[-lines:]


